const body = $json.body || $json;

function s(v) {
  return v == null ? '' : String(v).trim();
}

function arr(v) {
  if (Array.isArray(v)) return v.map(x => s(x)).filter(Boolean);
  if (typeof v === 'string' && v.trim()) {
    try {
      const parsed = JSON.parse(v);
      return arr(parsed);
    } catch {
      return [s(v)];
    }
  }
  return [];
}

const subjectRefs = Array.isArray(body.subject_refs) ? body.subject_refs : [];
const referenceImageUrls = arr(body.reference_image_urls || body.image_urls || body.images);
const productUrl = s(body.product_image_url) || s(subjectRefs.find(r => r?.type === 'product')?.url) || referenceImageUrls[0] || '';
const characterUrl = s(body.character_image_url || body.person_image_url) || s(subjectRefs.find(r => r?.type === 'character')?.url) || '';
const frameUrl = s(body.reference_frame_url) || referenceImageUrls.find(url => url !== productUrl && url !== characterUrl) || '';

return {
  json: {
    segment_id: s(body.segment_id),
    task_id: s(body.task_id),
    prompt: s(body.prompt),
    raw_prompt: s(body.raw_prompt),
    product_image_url: productUrl,
    character_image_url: characterUrl,
    reference_frame_url: frameUrl,
    subject_refs: subjectRefs,
    subject_replace_mode: s(body.subject_replace_mode || body.image_edit_mode),
    reference_image_urls: referenceImageUrls,
    images: referenceImageUrls,
    model: s(body.model || body.requested_model || 'image2'),
    requested_model: s(body.requested_model || body.model || 'image2'),
    model_capabilities: body.model_capabilities || {},
    aspect_ratio: s(body.aspect_ratio || '9:16'),
    callback_url: s(body.callback_url),
    api_key: s(body.api_key),
    admin_token: s(body.admin_token),
    workflow_id: s(body.workflow_id || 'flow_storyboard_image')
  }
};

const j = $json || {};

function s(v) {
  return v == null ? '' : String(v).trim();
}

function unique(values) {
  const seen = new Set();
  const out = [];
  for (const value of values) {
    const text = s(value);
    if (!text || seen.has(text)) continue;
    seen.add(text);
    out.push(text);
  }
  return out;
}

const rawPrompt = s(j.prompt);
const modelKey = s(j.model || j.requested_model || 'image2');
const provider = s(j.model_capabilities?.provider || '').toLowerCase();
const referenceUrls = unique([
  ...(Array.isArray(j.reference_image_urls) ? j.reference_image_urls : []),
  ...(Array.isArray(j.images) ? j.images : []),
  j.product_image_url,
  j.character_image_url,
  j.reference_frame_url,
]);

// =========================================================
// 1. Prompt 预处理 (信息图去文字专用)
// =========================================================
let cleanPrompt = rawPrompt;
cleanPrompt = cleanPrompt.replace(/(手写体|无衬线字体|手写风格)/g, '手绘线条和纹理');
cleanPrompt = cleanPrompt.replace(/(用手写风格展示手稿)/g, '用抽象线条模拟手稿');
cleanPrompt = cleanPrompt.replace(/(搭配无衬线字体的标题)/g, '搭配模块化的图形标题色块');

const parts = [];

parts.push({ 
  text: `PRIMARY VISUAL INSTRUCTION: 
  Create a pure visual graphic based on this modified prompt: "${cleanPrompt}". 

  STRICT NEGATIVE CONSTRAINT (HIGHEST PRIORITY): 
  - ABSOLUTELY NO TEXT, NO LETTERS, NO NUMBERS, NO ALPHABETS, NO WORDS, NO TYPOGRAPHY.
  - The image must contain ONLY visual elements, illustrations, graphics, icons, and textures.
  - If the prompt mentions "manuscripts" or "titles", represent them as abstract shapes, lines, dots, or color blocks, NOT as readable text.` 
});

if (j.person_image_b64) {
  parts.push({ text: 'CHARACTER IDENTITY: Use this person as the consistent subject.' });
  parts.push({ inline_data: { mime_type: s(j.person_mime_type || 'image/jpeg'), data: j.person_image_b64 } });
}

if (j.product_image_b64) {
  parts.push({ text: 'PRODUCT IDENTITY: Use this specific product, maintaining branding.' });
  parts.push({ inline_data: { mime_type: s(j.product_mime_type || 'image/jpeg'), data: j.product_image_b64 } });
}

if (j.reference_frame_b64) {
  parts.push({ text: 'LAYOUT REFERENCE: Use this as a guide for composition only. Ignore text.' });
  parts.push({ inline_data: { mime_type: s(j.reference_frame_mime || 'image/jpeg'), data: j.reference_frame_b64 } });
}

const systemCommand = `You are a world-class graphic designer. 
Your goal is to produce a CLEAN, HIGH-END visual image.
RULE #1: NEVER include any text, letters, numbers, or typography. This is the absolute rule.
RULE #2: Translate all prompt descriptions (like 'notes' or 'structure') into pure visual graphics or icons.
Priority: NO TEXT > Layout > Style.`;

parts.push({ text: systemCommand });

const request_body = {
  contents: [{ role: 'user', parts }],
  generationConfig: {
    responseModalities: ['IMAGE'],
    imageConfig: { aspectRatio: s(j.aspect_ratio || '9:16') }
  }
};

const modelMap = {
  image2: 'gemini-3-pro-image-preview',
  nanoBananapro: 'gemini-3-pro-image-preview',
  nanoBanana2: 'gemini-3.1-flash-image-preview'
};

return {
  json: {
    ...j,
    request_body,
    reference_image_urls: referenceUrls,
    images: referenceUrls,
    api_model: modelMap[modelKey] || (provider === 'gemini-image' ? modelKey : 'gemini-3-pro-image-preview'),
    model_used_by_workflow: modelKey
  }
};

function unwrapRoot(x) {
  if (x && typeof x === 'object' && x.body && typeof x.body === 'object') return x.body;
  return x;
}

function findInlineImageParts(root) {
  const candidates = root?.candidates;
  if (!Array.isArray(candidates) || !candidates.length) return [];
  const parts = candidates?.[0]?.content?.parts;
  if (!Array.isArray(parts)) return [];
  const imgs = [];
  for (const p of parts) {
    const inline = p?.inline_data || p?.inlineData;
    if (inline?.data) {
      imgs.push({ b64: inline.data, mimeType: inline.mime_type || inline.mimeType || 'image/png' });
      continue;
    }
    const fd = p?.fileData;
    if (fd?.fileUri) {
      imgs.push({ fileUri: fd.fileUri, mimeType: fd.mimeType || 'image/png' });
    }
  }
  return imgs;
}

function stripDataPrefix(b64) {
  return String(b64 || '').replace(/^data:.*;base64,/, '').trim();
}

const raw = $json || {};
const root = unwrapRoot(raw);
const imgs = findInlineImageParts(root);
const first = imgs[0];
if (!first || !first.b64) throw new Error('未从生图响应中解析到 inline image');

const mimeType = first.mimeType || 'image/png';
const ext = /png/i.test(mimeType) ? 'png' : (/webp/i.test(mimeType) ? 'webp' : 'jpg');
const b64 = stripDataPrefix(first.b64);
if (!b64) throw new Error('图片 base64 为空');

return {
  json: {
    mimeType,
    fileName: `storyboard_segment_${Date.now()}.${ext}`
  },
  binary: {
    data: {
      data: b64,
      mimeType,
      fileName: `storyboard_segment_${Date.now()}.${ext}`
    }
  }
};

const uploadResp = $input.item.json;
const imageUrl = uploadResp.url || '';

return {
  json: {
    image_url: imageUrl
  }
};

const j = $json || {};

function s(v) {
  return v == null ? '' : String(v);
}

async function readBinaryBase64(keyCandidates) {
  const keys = Object.keys($binary || {});
  let hitKey = '';

  for (const k of keyCandidates) {
    if (keys.includes(k)) {
      hitKey = k;
      break;
    }
  }

  if (!hitKey) return { ok: false, b64: '', mime: '' };

  try {
    const buf = await this.helpers.getBinaryDataBuffer(0, hitKey);
    const meta = $binary[hitKey] || {};
    return {
      ok: true,
      b64: buf.toString('base64'),
      mime: s(meta.mimeType || 'image/jpeg')
    };
  } catch (e) {
    return { ok: false, b64: '', mime: '' };
  }
}

const personImg = await readBinaryBase64(['person_file', 'character_file']);
const productImg = await readBinaryBase64(['product_file']);
const referenceImg = await readBinaryBase64(['reference_file', 'frame_file']);

return {
  json: {
    ...j,
    person_image_b64: personImg.b64,
    person_mime_type: personImg.mime,
    product_image_b64: productImg.b64,
    product_mime_type: productImg.mime,
    reference_frame_b64: referenceImg.b64,
    reference_frame_mime: referenceImg.mime
  },
  binary: $binary
};
